            // Normal edge traversal
            const newCost = cost + w;
            const newKey = `${v}_0`;
            if (!dist.has(newKey) || dist.get(newKey)! > newCost) {
                dist.set(newKey, newCost);
                pq.push([newCost, v, 0]);
            }

            // Reverse edge traversal if switch hasn't been used
            if (!hasSwitchUsed) {
                const reversedCost = cost + 2 * w;
                const reversedKey = `${v}_1`;
                if (!dist.has(reversedKey) || dist.get(reversedKey)! > reversedCost) {
                    dist.set(reversedKey, reversedCost);
                    pq.push([reversedCost, v, 1]);
                }
            }
        }
    }

    // If we can't reach the destination
    return -1;
}

